import { memo, useEffect, useRef, useState } from 'react';
import { ChevronDown, ChevronRight } from 'lucide-react';
import { Button } from '@/shared/components/ui/button';
import { Input } from '@/shared/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import AssetPanel from '@/tools/video-editor/components/PropertiesPanel/AssetPanel';
import { ClipPanel, getVisibleClipTabs } from '@/tools/video-editor/components/PropertiesPanel/ClipPanel';
import { useTimelineEditorContext } from '@/tools/video-editor/contexts/TimelineEditorContext';

type BulkMuteValue = 'mixed' | 'muted' | 'unmuted';

const getSharedValue = <T,>(values: T[]): T | null => {
  if (values.length === 0) {
    return null;
  }

  const [firstValue, ...rest] = values;
  return rest.every((value) => value === firstValue) ? firstValue : null;
};

function BulkClipPanel({
  clipIds,
  clipCount,
  initialOpacity,
  initialSpeed,
  initialMute,
  onChange,
  onClose,
}: {
  clipIds: string[];
  clipCount: number;
  initialOpacity: number | null;
  initialSpeed: number | null;
  initialMute: boolean | null;
  onChange: (patch: { opacity?: number; speed?: number; volume?: number }) => void;
  onClose: () => void;
}) {
  const [opacityDraft, setOpacityDraft] = useState(initialOpacity === null ? '' : String(initialOpacity));
  const [speedDraft, setSpeedDraft] = useState(initialSpeed === null ? '' : String(initialSpeed));
  const [muteValue, setMuteValue] = useState<BulkMuteValue>(
    initialMute === null ? 'mixed' : initialMute ? 'muted' : 'unmuted',
  );

  useEffect(() => {
    setOpacityDraft(initialOpacity === null ? '' : String(initialOpacity));
    setSpeedDraft(initialSpeed === null ? '' : String(initialSpeed));
    setMuteValue(initialMute === null ? 'mixed' : initialMute ? 'muted' : 'unmuted');
  }, [initialMute, initialOpacity, initialSpeed, clipIds]);

  const commitNumber = (field: 'opacity' | 'speed', value: string) => {
    if (value.trim() === '') {
      return;
    }

    const parsedValue = Number(value);
    if (!Number.isFinite(parsedValue)) {
      return;
    }

    onChange({
      [field]: field === 'opacity'
        ? Math.min(1, Math.max(0, parsedValue))
        : Math.max(0.05, parsedValue),
    });
  };

  return (
    <div className="space-y-3">
      <div className="flex items-start justify-between gap-3 rounded-xl border border-border bg-card/70 p-3">
        <div className="min-w-0">
          <div className="truncate text-sm font-medium text-foreground">
            {clipCount} clips selected
          </div>
          <div className="mt-1 text-[11px] uppercase tracking-[0.14em] text-muted-foreground">
            Bulk settings
          </div>
        </div>
        <Button type="button" variant="ghost" size="icon" className="h-8 w-8" onClick={onClose}>
          ×
        </Button>
      </div>

      <div className="grid gap-3 md:grid-cols-2">
        <div className="space-y-2">
          <div className="text-xs font-medium text-muted-foreground">Opacity</div>
          <Input
            type="number"
            min={0}
            max={1}
            step="0.05"
            value={opacityDraft}
            placeholder="Mixed"
            onChange={(event) => setOpacityDraft(event.target.value)}
            onBlur={() => commitNumber('opacity', opacityDraft)}
            onKeyDown={(event) => {
              if (event.key === 'Enter') {
                commitNumber('opacity', opacityDraft);
              }
            }}
          />
        </div>

        <div className="space-y-2">
          <div className="text-xs font-medium text-muted-foreground">Speed</div>
          <Input
            type="number"
            min={0.05}
            step="0.1"
            value={speedDraft}
            placeholder="Mixed"
            onChange={(event) => setSpeedDraft(event.target.value)}
            onBlur={() => commitNumber('speed', speedDraft)}
            onKeyDown={(event) => {
              if (event.key === 'Enter') {
                commitNumber('speed', speedDraft);
              }
            }}
          />
        </div>
      </div>

      <div className="space-y-2">
        <div className="text-xs font-medium text-muted-foreground">Mute</div>
        <Select
          value={muteValue}
          onValueChange={(value) => {
            const nextValue = value as BulkMuteValue;
            setMuteValue(nextValue);
            if (nextValue === 'mixed') {
              return;
            }

            onChange({ volume: nextValue === 'muted' ? 0 : 1 });
          }}
        >
          <SelectTrigger>
            <SelectValue placeholder="Mixed" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="mixed" disabled>Mixed</SelectItem>
            <SelectItem value="muted">Muted</SelectItem>
            <SelectItem value="unmuted">Unmuted</SelectItem>
          </SelectContent>
        </Select>
      </div>
    </div>
  );
}

function PropertiesPanelComponent() {
  const {
    data,
    resolvedConfig,
    selectedClip,
    selectedClipIds,
    selectedTrack,
    selectedClipHasPredecessor,
    compositionSize,
    clearSelection,
    setSelectedClipId,
    handleUpdateClips,
    handleDeleteClip,
    handleSelectedClipChange,
    handleResetClipPosition,
    handleToggleMute,
    preferences,
    setActiveClipTab,
    setAssetPanelState,
    uploadFiles,
  } = useTimelineEditorContext();
  const [assetsExpanded, setAssetsExpanded] = useState(false);
  const prevClipIdRef = useRef(selectedClip?.id);

  useEffect(() => {
    const nextVisibleTabs = getVisibleClipTabs(selectedClip, selectedTrack);
    const isClipChange = selectedClip?.id !== prevClipIdRef.current;

    if (isClipChange && selectedClip?.clipType === 'text') {
      setActiveClipTab('text');
    } else if (!nextVisibleTabs.includes(preferences.activeClipTab)) {
      setActiveClipTab('effects');
    }

    prevClipIdRef.current = selectedClip?.id;
  }, [preferences.activeClipTab, selectedClip, selectedTrack, setActiveClipTab]);

  const selectedClipIdsList = [...selectedClipIds];
  const bulkSelectedClips = resolvedConfig?.clips.filter((clip) => selectedClipIds.has(clip.id)) ?? [];
  const bulkOpacity = getSharedValue(bulkSelectedClips.map((clip) => clip.opacity ?? 1));
  const bulkSpeed = getSharedValue(bulkSelectedClips.map((clip) => clip.speed ?? 1));
  const bulkMute = getSharedValue(bulkSelectedClips.map((clip) => (clip.volume ?? 1) <= 0));

  if (!data) {
    return null;
  }

  return (
    <div className="flex h-full min-h-0 flex-col gap-3">
      <div className="overflow-hidden rounded-xl border border-border bg-card/80">
        <button
          type="button"
          className="flex w-full items-center gap-1.5 px-3 py-2 text-[11px] font-semibold uppercase tracking-[0.16em] text-muted-foreground transition-colors hover:bg-accent hover:text-foreground"
          onClick={() => setAssetsExpanded((value) => !value)}
        >
          {assetsExpanded ? <ChevronDown className="h-3.5 w-3.5" /> : <ChevronRight className="h-3.5 w-3.5" />}
          Assets
        </button>
        {assetsExpanded && (
          <div className="border-t border-border px-3 pb-3">
            <AssetPanel
              assetMap={data.assetMap}
              rows={data.rows}
              meta={data.meta}
              backgroundAsset={data.output.background ?? undefined}
              showAll={preferences.assetPanel.showAll}
              showHidden={preferences.assetPanel.showHidden}
              hidden={preferences.assetPanel.hidden}
              setPanelState={setAssetPanelState}
              onUploadFiles={uploadFiles}
              registry={data.registry.assets}
            />
          </div>
        )}
      </div>
      <div className="min-h-0 flex-1 overflow-auto rounded-xl border border-border bg-card/80 p-3">
        {selectedClipIds.size > 1 ? (
          <BulkClipPanel
            clipIds={selectedClipIdsList}
            clipCount={selectedClipIds.size}
            initialOpacity={bulkOpacity}
            initialSpeed={bulkSpeed}
            initialMute={bulkMute}
            onChange={(patch) => handleUpdateClips(selectedClipIdsList, patch)}
            onClose={clearSelection}
          />
        ) : (
          <ClipPanel
            clip={selectedClip}
            track={selectedTrack}
            hasPredecessor={selectedClipHasPredecessor}
            onChange={handleSelectedClipChange}
            onResetPosition={handleResetClipPosition}
            onClose={() => setSelectedClipId(null)}
            onDelete={selectedClip ? () => handleDeleteClip(selectedClip.id) : undefined}
            onToggleMute={handleToggleMute}
            compositionWidth={compositionSize.width}
            compositionHeight={compositionSize.height}
            activeTab={preferences.activeClipTab}
            setActiveTab={setActiveClipTab}
          />
        )}
      </div>
    </div>
  );
}

export const PropertiesPanel = memo(PropertiesPanelComponent);

import { useCallback, useMemo } from 'react';
import { addTrack } from '@/tools/video-editor/lib/editor-utils';
import { DEFAULT_VIDEO_TRACKS } from '@/tools/video-editor/lib/defaults';
import type { TrackDefinition, TrackKind } from '@/tools/video-editor/types';
import { moveClipBetweenTracks } from '@/tools/video-editor/lib/coordinate-utils';
import type { TimelineData } from '@/tools/video-editor/lib/timeline-data';
import { resolveOverlaps } from '@/tools/video-editor/lib/resolve-overlaps';
import type { UseTimelineDataResult } from '@/tools/video-editor/hooks/useTimelineData';

export interface UseTimelineTrackManagementArgs {
  dataRef: React.MutableRefObject<TimelineData | null>;
  resolvedConfig: TimelineData['resolvedConfig'] | null;
  selectedClipId: string | null;
  setSelectedTrackId: React.Dispatch<React.SetStateAction<string | null>>;
  applyTimelineEdit: UseTimelineDataResult['applyTimelineEdit'];
  applyResolvedConfigEdit: UseTimelineDataResult['applyResolvedConfigEdit'];
}

export interface UseTimelineTrackManagementResult {
  handleAddTrack: (kind: TrackKind) => void;
  handleTrackPopoverChange: (trackId: string, patch: Partial<TrackDefinition>) => void;
  handleReorderTrack: (trackId: string, direction: -1 | 1) => void;
  handleRemoveTrack: (trackId: string) => void;
  handleClearUnusedTracks: () => void;
  unusedTrackCount: number;
  moveClipToRow: (clipId: string, targetRowId: string, newStartTime?: number) => void;
  createTrackAndMoveClip: (clipId: string, kind: TrackKind, newStartTime?: number) => void;
  moveSelectedClipToTrack: (direction: 'up' | 'down') => void;
}

export function useTimelineTrackManagement({
  dataRef,
  resolvedConfig,
  selectedClipId,
  setSelectedTrackId,
  applyTimelineEdit,
  applyResolvedConfigEdit,
}: UseTimelineTrackManagementArgs): UseTimelineTrackManagementResult {
  const moveClipToRow = useCallback((clipId: string, targetRowId: string, newStartTime?: number) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    const sourceRow = current.rows.find((row) => row.actions.some((action) => action.id === clipId));
    const targetRow = current.rows.find((row) => row.id === targetRowId);
    if (!sourceRow || !targetRow) {
      return;
    }

    const sourceTrack = current.tracks.find((track) => track.id === sourceRow.id);
    const targetTrack = current.tracks.find((track) => track.id === targetRow.id);
    const action = sourceRow.actions.find((candidate) => candidate.id === clipId);
    if (!sourceTrack || !targetTrack || !action || sourceTrack.kind !== targetTrack.kind) {
      return;
    }

    const duration = action.end - action.start;
    const nextStart = typeof newStartTime === 'number' ? Math.max(0, newStartTime) : action.start;
    const nextAction = { ...action, start: nextStart, end: nextStart + duration };
    let placedRows = current.rows.map((row) => {
      if (sourceRow.id === targetRow.id && row.id === sourceRow.id) {
        return {
          ...row,
          actions: row.actions.map((candidate) => (candidate.id === clipId ? nextAction : candidate)),
        };
      }

      if (row.id === sourceRow.id) {
        return { ...row, actions: row.actions.filter((candidate) => candidate.id !== clipId) };
      }

      if (row.id === targetRow.id) {
        return { ...row, actions: [...row.actions, nextAction] };
      }

      return row;
    });

    // Trim the moved clip if it overlaps existing siblings
    const { rows: resolvedRows, metaPatches } = resolveOverlaps(
      placedRows, targetRow.id, clipId, current.meta,
    );

    const nextClipOrder = moveClipBetweenTracks(current.clipOrder, clipId, sourceRow.id, targetRow.id);
    applyTimelineEdit(
      resolvedRows,
      { [clipId]: { track: targetRow.id }, ...metaPatches },
      undefined,
      nextClipOrder,
    );
  }, [applyTimelineEdit, dataRef]);

  const createTrackAndMoveClip = useCallback((clipId: string, kind: TrackKind, newStartTime?: number) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    const sourceClip = current.resolvedConfig.clips.find((clip) => clip.id === clipId);
    const sourceTrack = sourceClip ? current.resolvedConfig.tracks.find((track) => track.id === sourceClip.track) : null;
    if (!sourceClip || !sourceTrack || sourceTrack.kind !== kind) {
      return;
    }

    const nextResolvedConfigBase = addTrack(current.resolvedConfig, kind);
    const newTrack = nextResolvedConfigBase.tracks.find((track) => {
      return !current.resolvedConfig.tracks.some((existingTrack) => existingTrack.id === track.id);
    }) ?? nextResolvedConfigBase.tracks[nextResolvedConfigBase.tracks.length - 1];
    if (!newTrack) {
      return;
    }

    const nextResolvedConfig = {
      ...nextResolvedConfigBase,
      clips: nextResolvedConfigBase.clips.map((clip) => {
        if (clip.id !== clipId) {
          return clip;
        }

        return {
          ...clip,
          at: typeof newStartTime === 'number' ? Math.max(0, newStartTime) : clip.at,
          track: newTrack.id,
        };
      }),
    };

    applyResolvedConfigEdit(nextResolvedConfig, {
      selectedClipId: clipId,
      selectedTrackId: newTrack.id,
    });
  }, [applyResolvedConfigEdit, dataRef]);

  const moveSelectedClipToTrack = useCallback((direction: 'up' | 'down') => {
    const current = dataRef.current;
    if (!current || !selectedClipId) {
      return;
    }

    const currentRowIndex = current.rows.findIndex((row) => row.actions.some((action) => action.id === selectedClipId));
    if (currentRowIndex < 0) {
      return;
    }

    const sourceTrack = current.tracks.find((track) => track.id === current.rows[currentRowIndex]?.id);
    if (!sourceTrack) {
      return;
    }

    let targetRowIndex = currentRowIndex;
    while (true) {
      targetRowIndex += direction === 'up' ? -1 : 1;
      if (targetRowIndex < 0 || targetRowIndex >= current.rows.length) {
        return;
      }

      const targetTrack = current.tracks.find((track) => track.id === current.rows[targetRowIndex]?.id);
      if (targetTrack?.kind === sourceTrack.kind) {
        moveClipToRow(selectedClipId, targetTrack.id);
        setSelectedTrackId(targetTrack.id);
        return;
      }
    }
  }, [dataRef, moveClipToRow, selectedClipId, setSelectedTrackId]);

  const handleAddTrack = useCallback((kind: TrackKind) => {
    if (!resolvedConfig) {
      return;
    }

    const nextResolvedConfig = addTrack(resolvedConfig, kind);
    const nextTrack = nextResolvedConfig.tracks[nextResolvedConfig.tracks.length - 1] ?? null;
    applyResolvedConfigEdit(nextResolvedConfig, { selectedTrackId: nextTrack?.id ?? null });
  }, [applyResolvedConfigEdit, resolvedConfig]);

  const handleTrackPopoverChange = useCallback((trackId: string, patch: Partial<TrackDefinition>) => {
    if (!resolvedConfig) {
      return;
    }

    const nextConfig = {
      ...resolvedConfig,
      tracks: resolvedConfig.tracks.map((track) => (track.id === trackId ? { ...track, ...patch } : track)),
    };
    applyResolvedConfigEdit(nextConfig, { selectedTrackId: trackId });
  }, [applyResolvedConfigEdit, resolvedConfig]);

  const handleReorderTrack = useCallback((trackId: string, direction: -1 | 1) => {
    if (!resolvedConfig) {
      return;
    }

    const index = resolvedConfig.tracks.findIndex((track) => track.id === trackId);
    if (index < 0) {
      return;
    }

    const targetIndex = index + direction;
    if (targetIndex < 0 || targetIndex >= resolvedConfig.tracks.length) {
      return;
    }

    if (resolvedConfig.tracks[index].kind !== resolvedConfig.tracks[targetIndex].kind) {
      return;
    }

    const nextTracks = [...resolvedConfig.tracks];
    [nextTracks[index], nextTracks[targetIndex]] = [nextTracks[targetIndex], nextTracks[index]];
    applyResolvedConfigEdit({ ...resolvedConfig, tracks: nextTracks }, { selectedTrackId: trackId });
  }, [applyResolvedConfigEdit, resolvedConfig]);

  const handleRemoveTrack = useCallback((trackId: string) => {
    if (!resolvedConfig) {
      return;
    }

    const track = resolvedConfig.tracks.find((entry) => entry.id === trackId);
    if (!track) {
      return;
    }

    const sameKind = resolvedConfig.tracks.filter((entry) => entry.kind === track.kind);
    if (sameKind.length <= 1) {
      return;
    }

    const nextConfig = {
      ...resolvedConfig,
      tracks: resolvedConfig.tracks.filter((entry) => entry.id !== trackId),
      clips: resolvedConfig.clips.filter((clip) => clip.track !== trackId),
    };
    applyResolvedConfigEdit(nextConfig, { selectedTrackId: null });
  }, [applyResolvedConfigEdit, resolvedConfig]);

  const unusedTrackCount = useMemo(() => {
    if (!resolvedConfig) {
      return 0;
    }

    const tracksWithClips = new Set(resolvedConfig.clips.map((clip) => clip.track));
    const defaultTrackIds = new Set(DEFAULT_VIDEO_TRACKS.map((track) => track.id));
    return resolvedConfig.tracks.filter((track) => !tracksWithClips.has(track.id) && !defaultTrackIds.has(track.id)).length;
  }, [resolvedConfig]);

  const handleClearUnusedTracks = useCallback(() => {
    if (!resolvedConfig || unusedTrackCount === 0) {
      return;
    }

    const tracksWithClips = new Set(resolvedConfig.clips.map((clip) => clip.track));
    const defaultTrackIds = new Set(DEFAULT_VIDEO_TRACKS.map((track) => track.id));
    const visualWithClips = resolvedConfig.tracks.filter((track) => track.kind === 'visual' && tracksWithClips.has(track.id));
    const audioWithClips = resolvedConfig.tracks.filter((track) => track.kind === 'audio' && tracksWithClips.has(track.id));

    const nextTracks = resolvedConfig.tracks.filter((track) => {
      if (defaultTrackIds.has(track.id)) {
        return true;
      }

      if (tracksWithClips.has(track.id)) {
        return true;
      }

      if (track.kind === 'visual' && visualWithClips.length === 0) {
        visualWithClips.push(track);
        return true;
      }

      if (track.kind === 'audio' && audioWithClips.length === 0) {
        audioWithClips.push(track);
        return true;
      }

      return false;
    });

    applyResolvedConfigEdit({ ...resolvedConfig, tracks: nextTracks }, { selectedTrackId: null });
  }, [applyResolvedConfigEdit, resolvedConfig, unusedTrackCount]);

  return {
    handleAddTrack,
    handleTrackPopoverChange,
    handleReorderTrack,
    handleRemoveTrack,
    handleClearUnusedTracks,
    unusedTrackCount,
    moveClipToRow,
    createTrackAndMoveClip,
    moveSelectedClipToTrack,
  };
}

import { useCallback, useLayoutEffect, useRef } from 'react';
import type { Dispatch, MutableRefObject, SetStateAction } from 'react';
import {
  getVisualTracks,
  splitClipAtPlayhead,
  updateClipInConfig,
} from '@/tools/video-editor/lib/editor-utils';
import {
  updateClipOrder,
} from '@/tools/video-editor/lib/coordinate-utils';
import {
  getNextClipId,
  type ClipMeta,
  type TimelineData,
} from '@/tools/video-editor/lib/timeline-data';
import type { UseTimelineDataResult } from '@/tools/video-editor/hooks/useTimelineData';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';

export interface UseClipEditingArgs {
  dataRef: MutableRefObject<TimelineData | null>;
  resolvedConfig: TimelineData['resolvedConfig'] | null;
  selectedClipId: string | null;
  selectedTrack: UseTimelineDataResult['selectedTrack'];
  currentTime: number;
  setSelectedClipId: Dispatch<SetStateAction<string | null>>;
  setSelectedTrackId: Dispatch<SetStateAction<string | null>>;
  applyTimelineEdit: UseTimelineDataResult['applyTimelineEdit'];
  applyResolvedConfigEdit: UseTimelineDataResult['applyResolvedConfigEdit'];
}

export interface UseClipEditingResult {
  onOverlayChange: (actionId: string, patch: Partial<ClipMeta>) => void;
  handleUpdateClips: (clipIds: string[], patch: Partial<ClipMeta>) => void;
  handleDeleteClips: (clipIds: string[]) => void;
  handleDeleteClip: (clipId: string) => void;
  handleSelectedClipChange: (patch: Partial<ClipMeta> & { at?: number }) => void;
  handleResetClipPosition: () => void;
  handleSplitSelectedClip: () => void;
  handleSplitClipAtTime: (clipId: string, timeSeconds: number) => void;
  handleToggleMuteClips: (clipIds: string[]) => void;
  handleToggleMute: () => void;
  handleAddText: () => void;
}

export function useClipEditing({
  dataRef,
  resolvedConfig,
  selectedClipId,
  selectedTrack,
  currentTime,
  setSelectedClipId,
  setSelectedTrackId,
  applyTimelineEdit,
  applyResolvedConfigEdit,
}: UseClipEditingArgs): UseClipEditingResult {
  const currentTimeRef = useRef(currentTime);

  useLayoutEffect(() => {
    currentTimeRef.current = currentTime;
  }, [currentTime]);

  const onOverlayChange = useCallback((actionId: string, patch: Partial<ClipMeta>) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    applyTimelineEdit(current.rows, { [actionId]: patch });
  }, [applyTimelineEdit, dataRef]);

  const getValidClipIds = useCallback((clipIds: string[]) => {
    const current = dataRef.current;
    if (!current) {
      return [];
    }

    const uniqueClipIds = new Set<string>();
    for (const clipId of clipIds) {
      if (clipId.startsWith('uploading-') || !current.meta[clipId]) {
        continue;
      }

      uniqueClipIds.add(clipId);
    }

    return [...uniqueClipIds];
  }, [dataRef]);

  const handleUpdateClips = useCallback((clipIds: string[], patch: Partial<ClipMeta>) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    const validClipIds = getValidClipIds(clipIds);
    if (validClipIds.length === 0) {
      return;
    }

    const metaUpdates = Object.fromEntries(
      validClipIds.map((clipId) => [clipId, patch]),
    ) as Record<string, Partial<ClipMeta>>;

    applyTimelineEdit(current.rows, metaUpdates);
  }, [applyTimelineEdit, dataRef, getValidClipIds]);

  const handleDeleteClips = useCallback((clipIds: string[]) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    const clipIdSet = new Set(getValidClipIds(clipIds));
    if (clipIdSet.size === 0) {
      return;
    }

    const nextRows = current.rows.map((row) => ({
      ...row,
      actions: row.actions.filter((action) => !clipIdSet.has(action.id)),
    }));
    applyTimelineEdit(nextRows, undefined, [...clipIdSet]);
  }, [applyTimelineEdit, dataRef, getValidClipIds]);

  const handleDeleteClip = useCallback((clipId: string) => {
    handleDeleteClips([clipId]);
  }, [handleDeleteClips]);

  const handleSelectedClipChange = useCallback((patch: Partial<ClipMeta> & { at?: number }) => {
    const current = dataRef.current;
    if (!current || !selectedClipId) {
      return;
    }

    const clipRow = current.rows.find((row) => row.actions.some((action) => action.id === selectedClipId));
    if (!clipRow) {
      return;
    }

    const nextRows = current.rows.map((row) => {
      if (row.id !== clipRow.id || patch.at === undefined) {
        return row;
      }

      return {
        ...row,
        actions: row.actions.map((action) => {
          if (action.id !== selectedClipId) {
            return action;
          }

          const duration = action.end - action.start;
          return {
            ...action,
            start: patch.at,
            end: patch.at + duration,
          };
        }),
      };
    });

    const { at: _at, ...metaPatch } = patch;
    applyTimelineEdit(nextRows, { [selectedClipId]: metaPatch });
  }, [applyTimelineEdit, dataRef, selectedClipId]);

  const handleResetClipPosition = useCallback(() => {
    if (!selectedClipId || !resolvedConfig) {
      return;
    }

    const nextConfig = updateClipInConfig(resolvedConfig, selectedClipId, (clip) => ({
      ...clip,
      x: undefined,
      y: undefined,
      width: undefined,
      height: undefined,
      cropTop: undefined,
      cropBottom: undefined,
      cropLeft: undefined,
      cropRight: undefined,
    }));
    applyResolvedConfigEdit(nextConfig, { selectedClipId });
  }, [applyResolvedConfigEdit, resolvedConfig, selectedClipId]);

  const handleSplitSelectedClip = useCallback(() => {
    if (!selectedClipId || !resolvedConfig) {
      return;
    }

    const splitResult = splitClipAtPlayhead(resolvedConfig, selectedClipId, currentTimeRef.current);
    if (!splitResult.nextSelectedClipId) {
      return;
    }

    applyResolvedConfigEdit(splitResult.config, { selectedClipId: splitResult.nextSelectedClipId });
  }, [applyResolvedConfigEdit, resolvedConfig, selectedClipId]);

  const handleSplitClipAtTime = useCallback((clipId: string, timeSeconds: number) => {
    if (!resolvedConfig) {
      return;
    }

    const splitResult = splitClipAtPlayhead(resolvedConfig, clipId, timeSeconds);
    if (!splitResult.nextSelectedClipId) {
      return;
    }

    applyResolvedConfigEdit(splitResult.config, { selectedClipId: splitResult.nextSelectedClipId });
  }, [applyResolvedConfigEdit, resolvedConfig]);

  const handleToggleMuteClips = useCallback((clipIds: string[]) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    const validClipIds = getValidClipIds(clipIds);
    if (validClipIds.length === 0) {
      return;
    }

    const metaUpdates = Object.fromEntries(
      validClipIds.map((clipId) => {
        const volume = current.meta[clipId]?.volume ?? 1;
        return [clipId, { volume: volume <= 0 ? 1 : 0 }];
      }),
    ) as Record<string, Partial<ClipMeta>>;

    applyTimelineEdit(current.rows, metaUpdates);
  }, [applyTimelineEdit, dataRef, getValidClipIds]);

  const handleToggleMute = useCallback(() => {
    if (!selectedClipId || !resolvedConfig) {
      return;
    }

    handleToggleMuteClips([selectedClipId]);
  }, [handleToggleMuteClips, resolvedConfig, selectedClipId]);

  const handleAddText = useCallback(() => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    const visualTrack = selectedTrack?.kind === 'visual'
      ? selectedTrack
      : getVisualTracks(current.resolvedConfig)[0];
    if (!visualTrack) {
      return;
    }

    const clipId = getNextClipId(current.meta);
    const action: TimelineAction = {
      id: clipId,
      start: currentTimeRef.current,
      end: currentTimeRef.current + 5,
      effectId: `effect-${clipId}`,
    };
    const nextRows = current.rows.map((row) => (
      row.id === visualTrack.id
        ? { ...row, actions: [...row.actions, action] }
        : row
    ));
    const nextClipOrder = updateClipOrder(current.clipOrder, visualTrack.id, (ids) => [...ids, clipId]);
    applyTimelineEdit(nextRows, {
      [clipId]: {
        track: visualTrack.id,
        clipType: 'text',
        text: {
          content: 'Double-click to edit',
          fontSize: 64,
          color: '#ffffff',
          align: 'center',
        },
        x: 120,
        y: 120,
        width: 640,
        height: 180,
        opacity: 1,
      },
    }, undefined, nextClipOrder);
    setSelectedClipId(clipId);
    setSelectedTrackId(visualTrack.id);
  }, [applyTimelineEdit, dataRef, selectedTrack, setSelectedClipId, setSelectedTrackId]);

  return {
    onOverlayChange,
    handleUpdateClips,
    handleDeleteClips,
    handleDeleteClip,
    handleSelectedClipChange,
    handleResetClipPosition,
    handleSplitSelectedClip,
    handleSplitClipAtTime,
    handleToggleMuteClips,
    handleToggleMute,
    handleAddText,
  };
}

import { useCallback, useLayoutEffect, useMemo } from 'react';
