import { useEffect, useMemo, useState } from 'react';
import { Volume2, Wand2 } from 'lucide-react';
import { Button } from '@/shared/components/ui/button';
import { cn } from '@/shared/components/ui/contracts/cn';
import { Input } from '@/shared/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { Slider } from '@/shared/components/ui/slider';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/shared/components/ui/tabs';
import { CustomEffectEditor } from '@/tools/video-editor/components/CustomEffectEditor';
import {
  FieldLabel,
  NO_EFFECT,
  TAB_COLUMNS_CLASS,
} from '@/tools/video-editor/components/PropertiesPanel/ClipPanel';
import { continuousEffectTypes, entranceEffectTypes, exitEffectTypes } from '@/tools/video-editor/effects';
import type { ClipTab } from '@/tools/video-editor/hooks/useTimelineData';
import type { ClipMeta } from '@/tools/video-editor/lib/timeline-data';
import type { ResolvedTimelineClip } from '@/tools/video-editor/types';

const MIXED_SELECT_VALUE = '__mixed__';

type BulkScalarPatch = Partial<Pick<ClipMeta, 'speed' | 'from' | 'to' | 'x' | 'y' | 'width' | 'height' | 'opacity' | 'volume'>>;
type BulkDraftField = 'speed' | 'from' | 'to' | 'x' | 'y' | 'width' | 'height' | 'fontSize' | 'color';
type BulkDrafts = Record<BulkDraftField, string>;

export interface BulkClipPanelProps {
  clips: ResolvedTimelineClip[];
  visibleTabs: ClipTab[];
  compositionWidth: number;
  compositionHeight: number;
  sharedEntrance: ResolvedTimelineClip['entrance'] | null;
  sharedExit: ResolvedTimelineClip['exit'] | null;
  sharedContinuous: ResolvedTimelineClip['continuous'] | null;
  sharedText: ResolvedTimelineClip['text'] | null;
  sharedEntranceType: string | null;
  sharedExitType: string | null;
  sharedContinuousType: string | null;
  sharedSpeed: number | null;
  sharedFrom: number | null;
  sharedTo: number | null;
  sharedX: number | null;
  sharedY: number | null;
  sharedWidth: number | null;
  sharedHeight: number | null;
  sharedOpacity: number | null;
  sharedVolume: number | null;
  sharedFontSize: number | null;
  sharedTextColor: string | null;
  onChange: (patch: BulkScalarPatch) => void;
  onChangeDeep: (patchFn: (existing: ClipMeta) => Partial<ClipMeta>) => void;
  onResetPosition: () => void;
  onToggleMute: () => void;
  onClose: () => void;
  activeTab: ClipTab;
  setActiveTab: (tab: ClipTab) => void;
}

const toDraft = (value: number | string | null): string => (value === null ? '' : String(value));

const buildDrafts = (props: BulkClipPanelProps): BulkDrafts => ({
  speed: toDraft(props.sharedSpeed),
  from: toDraft(props.sharedFrom),
  to: toDraft(props.sharedTo),
  x: toDraft(props.sharedX),
  y: toDraft(props.sharedY),
  width: toDraft(props.sharedWidth),
  height: toDraft(props.sharedHeight),
  fontSize: toDraft(props.sharedFontSize ?? props.sharedText?.fontSize ?? null),
  color: toDraft(props.sharedTextColor ?? props.sharedText?.color ?? null),
});

export function BulkClipPanel(props: BulkClipPanelProps) {
  const {
    clips,
    visibleTabs,
    compositionWidth,
    compositionHeight,
    sharedEntrance,
    sharedExit,
    sharedContinuous,
    sharedText,
    sharedEntranceType,
    sharedExitType,
    sharedContinuousType,
    sharedOpacity,
    sharedVolume,
    onChange,
    onChangeDeep,
    onResetPosition,
    onToggleMute,
    onClose,
    activeTab,
    setActiveTab,
  } = props;
  const [showCustomEditor, setShowCustomEditor] = useState(false);
  const [drafts, setDrafts] = useState<BulkDrafts>(() => buildDrafts(props));

  const sharedCustomEffect = useMemo(() => {
    const candidates = [
      { category: 'continuous' as const, value: sharedContinuous?.type },
      { category: 'entrance' as const, value: sharedEntrance?.type },
      { category: 'exit' as const, value: sharedExit?.type },
    ];

    for (const candidate of candidates) {
      if (candidate.value?.startsWith('custom:')) {
        return {
          category: candidate.category,
          slug: candidate.value.replace(/^custom:/, ''),
        };
      }
    }

    return null;
  }, [sharedContinuous, sharedEntrance, sharedExit]);

  useEffect(() => {
    setDrafts(buildDrafts(props));
  }, [
    props.compositionHeight,
    props.compositionWidth,
    props.sharedFrom,
    props.sharedFontSize,
    props.sharedHeight,
    props.sharedSpeed,
    props.sharedText,
    props.sharedTextColor,
    props.sharedTo,
    props.sharedWidth,
    props.sharedX,
    props.sharedY,
  ]);

  useEffect(() => {
    if (!visibleTabs.includes(activeTab)) {
      setActiveTab('effects');
    }
  }, [activeTab, setActiveTab, visibleTabs]);

  useEffect(() => {
    if (!sharedCustomEffect) {
      setShowCustomEditor(false);
    }
  }, [sharedCustomEffect]);

  const setDraft = (field: BulkDraftField, value: string) => {
    setDrafts((current) => ({ ...current, [field]: value }));
  };

  const commitScalarField = (field: Exclude<BulkDraftField, 'fontSize' | 'color'>, value: string) => {
    if (value.trim() === '') {
      return;
    }

    const parsedValue = Number(value);
    if (!Number.isFinite(parsedValue)) {
      return;
    }

    switch (field) {
      case 'speed':
        onChange({ speed: Math.max(0.05, parsedValue) });
        return;
      case 'from':
        onChange({ from: Math.max(0, parsedValue) });
        return;
      case 'to':
        onChange({ to: Math.max(0, parsedValue) });
        return;
      case 'x':
        onChange({ x: parsedValue });
        return;
      case 'y':
        onChange({ y: parsedValue });
        return;
      case 'width':
        onChange({ width: Math.min(compositionWidth, Math.max(0, parsedValue)) });
        return;
      case 'height':
        onChange({ height: Math.min(compositionHeight, Math.max(0, parsedValue)) });
        return;
      default:
        return;
    }
  };

  const commitTextFontSize = (value: string) => {
    if (value.trim() === '') {
      return;
    }

    const parsedValue = Number(value);
    if (!Number.isFinite(parsedValue)) {
      return;
    }

    onChangeDeep((meta) => ({
      text: {
        ...(meta.text ?? sharedText ?? { content: '' }),
        fontSize: Math.max(1, parsedValue),
      },
    }));
  };

  const commitTextColor = (value: string) => {
    const normalized = value.trim();
    if (normalized === '') {
      return;
    }

    onChangeDeep((meta) => ({
      text: {
        ...(meta.text ?? sharedText ?? { content: '' }),
        color: normalized,
      },
    }));
  };

  const renderNumberInput = (
    field: Exclude<BulkDraftField, 'fontSize' | 'color'>,
    label: string,
    options?: { min?: number; max?: number; step?: number },
  ) => (
    <div className="space-y-2">
      <FieldLabel>{label}</FieldLabel>
      <Input
        type="number"
        min={options?.min}
        max={options?.max}
        step={options?.step}
        value={drafts[field]}
        placeholder="Mixed"
        onChange={(event) => setDraft(field, event.target.value)}
        onBlur={() => commitScalarField(field, drafts[field])}
        onKeyDown={(event) => {
          if (event.key === 'Enter') {
            commitScalarField(field, drafts[field]);
          }
        }}
      />
    </div>
  );

  return (
    <div className="space-y-3">
      <div className="flex items-start justify-between gap-3 rounded-xl border border-border bg-card/70 p-3">
        <div className="min-w-0">
          <div className="truncate text-sm font-medium text-foreground">
            {clips.length} clips selected
          </div>
          <div className="mt-1 text-[11px] uppercase tracking-[0.14em] text-muted-foreground">
            Bulk settings
          </div>
        </div>
        <Button type="button" variant="ghost" size="icon" className="h-8 w-8" onClick={onClose}>
          ×
        </Button>
      </div>

      <Tabs value={activeTab} onValueChange={(value) => setActiveTab(value as ClipTab)}>

import { memo, useEffect, useRef, useState } from 'react';
import { ChevronDown, ChevronRight } from 'lucide-react';
import AssetPanel from '@/tools/video-editor/components/PropertiesPanel/AssetPanel';
import { BulkClipPanel } from '@/tools/video-editor/components/PropertiesPanel/BulkClipPanel';
import { ClipPanel, getVisibleClipTabs, NO_EFFECT } from '@/tools/video-editor/components/PropertiesPanel/ClipPanel';
import { useTimelineEditorContext } from '@/tools/video-editor/contexts/TimelineEditorContext';
import { getBulkVisibleTabs, getSharedNestedValue, getSharedValue } from '@/tools/video-editor/lib/bulk-utils';

function PropertiesPanelComponent() {
  const {
    data,
    resolvedConfig,
    selectedClip,
    selectedClipIds,
    selectedTrack,
    selectedClipHasPredecessor,
    compositionSize,
    clearSelection,
    setSelectedClipId,
    handleUpdateClips,
    handleUpdateClipsDeep,
    handleDeleteClip,
    handleSelectedClipChange,
    handleResetClipPosition,
    handleResetClipsPosition,
    handleToggleMuteClips,
    handleToggleMute,
    preferences,
    setActiveClipTab,
    setAssetPanelState,
    uploadFiles,
  } = useTimelineEditorContext();
  const [assetsExpanded, setAssetsExpanded] = useState(false);
  const prevClipIdRef = useRef(selectedClip?.id);
  const selectedClipIdsList = [...selectedClipIds];
  const bulkSelectedClips = resolvedConfig?.clips.filter((clip) => selectedClipIds.has(clip.id)) ?? [];
  const bulkVisibleTabs = getBulkVisibleTabs(bulkSelectedClips, data?.resolvedConfig?.tracks ?? []);
  const bulkEntrance = getSharedNestedValue(bulkSelectedClips, (clip) => clip.entrance);
  const bulkExit = getSharedNestedValue(bulkSelectedClips, (clip) => clip.exit);
  const bulkContinuous = getSharedNestedValue(bulkSelectedClips, (clip) => clip.continuous);
  const bulkText = getSharedNestedValue(bulkSelectedClips, (clip) => clip.text);
  const bulkEntranceType = getSharedValue(bulkSelectedClips.map((clip) => clip.entrance?.type ?? NO_EFFECT));
  const bulkExitType = getSharedValue(bulkSelectedClips.map((clip) => clip.exit?.type ?? NO_EFFECT));
  const bulkContinuousType = getSharedValue(bulkSelectedClips.map((clip) => clip.continuous?.type ?? NO_EFFECT));
  const bulkSpeed = getSharedValue(bulkSelectedClips.map((clip) => clip.speed ?? 1));
  const bulkFrom = getSharedValue(bulkSelectedClips.map((clip) => clip.from ?? 0));
  const bulkTo = getSharedValue(bulkSelectedClips.map((clip) => clip.to ?? clip.assetEntry?.duration ?? 5));
  const bulkX = getSharedValue(bulkSelectedClips.map((clip) => clip.x ?? 0));
  const bulkY = getSharedValue(bulkSelectedClips.map((clip) => clip.y ?? 0));
  const bulkWidth = getSharedValue(bulkSelectedClips.map((clip) => clip.width ?? compositionSize.width));
  const bulkHeight = getSharedValue(bulkSelectedClips.map((clip) => clip.height ?? compositionSize.height));
  const bulkOpacity = getSharedValue(bulkSelectedClips.map((clip) => clip.opacity ?? 1));
  const bulkVolume = getSharedValue(bulkSelectedClips.map((clip) => clip.volume ?? 1));
  const bulkFontSize = getSharedValue(bulkSelectedClips.map((clip) => clip.text?.fontSize ?? 64));
  const bulkTextColor = getSharedValue(bulkSelectedClips.map((clip) => clip.text?.color ?? '#ffffff'));

  useEffect(() => {
    if (selectedClipIds.size > 1) {
      if (!bulkVisibleTabs.includes(preferences.activeClipTab)) {
        setActiveClipTab('effects');
      }
      return;
    }

    const nextVisibleTabs = getVisibleClipTabs(selectedClip, selectedTrack);
    const isClipChange = selectedClip?.id !== prevClipIdRef.current;

    if (isClipChange && selectedClip?.clipType === 'text') {
      setActiveClipTab('text');
    } else if (!nextVisibleTabs.includes(preferences.activeClipTab)) {
      setActiveClipTab('effects');
    }

    prevClipIdRef.current = selectedClip?.id;
  }, [
    bulkVisibleTabs,
    preferences.activeClipTab,
    selectedClip,
    selectedClipIds.size,
    selectedTrack,
    setActiveClipTab,
  ]);

  if (!data) {
    return null;
  }

  return (
    <div className="flex h-full min-h-0 flex-col gap-3">
      <div className="overflow-hidden rounded-xl border border-border bg-card/80">
        <button
          type="button"
          className="flex w-full items-center gap-1.5 px-3 py-2 text-[11px] font-semibold uppercase tracking-[0.16em] text-muted-foreground transition-colors hover:bg-accent hover:text-foreground"
          onClick={() => setAssetsExpanded((value) => !value)}
        >
          {assetsExpanded ? <ChevronDown className="h-3.5 w-3.5" /> : <ChevronRight className="h-3.5 w-3.5" />}
          Assets
        </button>
        {assetsExpanded && (
          <div className="border-t border-border px-3 pb-3">
            <AssetPanel
              assetMap={data.assetMap}
              rows={data.rows}
              meta={data.meta}
              backgroundAsset={data.output.background ?? undefined}
              showAll={preferences.assetPanel.showAll}
              showHidden={preferences.assetPanel.showHidden}
              hidden={preferences.assetPanel.hidden}
              setPanelState={setAssetPanelState}
              onUploadFiles={uploadFiles}
              registry={data.registry.assets}
            />
          </div>
        )}
      </div>
      <div className="min-h-0 flex-1 overflow-auto rounded-xl border border-border bg-card/80 p-3">
        {selectedClipIds.size > 1 ? (
          <BulkClipPanel
            clips={bulkSelectedClips}
            visibleTabs={bulkVisibleTabs}
            compositionWidth={compositionSize.width}
            compositionHeight={compositionSize.height}
            sharedEntrance={bulkEntrance}
            sharedExit={bulkExit}
            sharedContinuous={bulkContinuous}
            sharedText={bulkText}
            sharedEntranceType={bulkEntranceType}
            sharedExitType={bulkExitType}
            sharedContinuousType={bulkContinuousType}
            sharedSpeed={bulkSpeed}
            sharedFrom={bulkFrom}
            sharedTo={bulkTo}
            sharedX={bulkX}
            sharedY={bulkY}
            sharedWidth={bulkWidth}
            sharedHeight={bulkHeight}
            sharedOpacity={bulkOpacity}
            sharedVolume={bulkVolume}
            sharedFontSize={bulkFontSize}
            sharedTextColor={bulkTextColor}
            onChange={(patch) => handleUpdateClips(selectedClipIdsList, patch)}
            onChangeDeep={(patchFn) => handleUpdateClipsDeep(selectedClipIdsList, patchFn)}
            onResetPosition={() => handleResetClipsPosition(selectedClipIdsList)}
            onToggleMute={() => handleToggleMuteClips(selectedClipIdsList)}
            onClose={clearSelection}
            activeTab={preferences.activeClipTab}
            setActiveTab={setActiveClipTab}
          />
        ) : (
          <ClipPanel
            clip={selectedClip}
            track={selectedTrack}
            hasPredecessor={selectedClipHasPredecessor}
            onChange={handleSelectedClipChange}
            onResetPosition={handleResetClipPosition}
            onClose={() => setSelectedClipId(null)}
            onDelete={selectedClip ? () => handleDeleteClip(selectedClip.id) : undefined}
            onToggleMute={handleToggleMute}
            compositionWidth={compositionSize.width}
            compositionHeight={compositionSize.height}
            activeTab={preferences.activeClipTab}
            setActiveTab={setActiveClipTab}
          />
        )}
      </div>
    </div>
  );
}

export const PropertiesPanel = memo(PropertiesPanelComponent);

